<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Sorting Visualizer</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #0f0f1a;
    color: #e0e0e0;
    font-family: 'Segoe UI', system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    min-height: 100vh;
    padding: 20px;
  }
  h1 { margin-bottom: 16px; font-size: 1.5rem; color: #a0c4ff; }
  .controls {
    display: flex;
    gap: 12px;
    margin-bottom: 20px;
  }
  button {
    padding: 10px 24px;
    border: none;
    border-radius: 6px;
    font-size: 1rem;
    cursor: pointer;
    background: #2a2a4a;
    color: #e0e0e0;
    transition: background 0.2s;
  }
  button:hover { background: #3a3a6a; }
  button#sort { background: #1a5c2a; }
  button#sort:hover { background: #2a7c3a; }
  button#shuffle { background: #5c4a1a; }
  button#shuffle:hover { background: #7c6a2a; }
  button#reset { background: #4a1a3a; }
  button#reset:hover { background: #6a2a5a; }
  #bars {
    display: flex;
    align-items: flex-end;
    gap: 2px;
    width: 90%;
    max-width: 900px;
    height: 400px;
    border-bottom: 2px solid #333;
    padding: 0 4px;
  }
  .bar {
    flex: 1;
    background: linear-gradient(to top, #4a90d9, #7b68ee);
    border-radius: 3px 3px 0 0;
    transition: height 0.15s ease;
    min-width: 2px;
  }
</style>
</head>
<body>
<h1>Sorting Visualizer</h1>
<div class="controls">
  <button id="sort">Sort</button>
  <button id="shuffle">Shuffle</button>
  <button id="reset">Reset</button>
</div>
<div id="bars"></div>

<script>
(function() {
  const barsContainer = document.getElementById('bars');

  let arr = [];
  // Bubble sort state: tracks current pass and element index
  let sortState = null;

  function render() {
    barsContainer.innerHTML = '';
    if (arr.length === 0) return;
    const maxVal = Math.max(...arr);
    for (let i = 0; i < arr.length; i++) {
      const bar = document.createElement('div');
      bar.className = 'bar';
      bar.style.height = ((arr[i] / maxVal) * 100) + '%';
      barsContainer.appendChild(bar);
    }
  }

  function shuffleArray(a) {
    for (let i = a.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [a[i], a[j]] = [a[j], a[i]];
    }
    return a;
  }

  function initSortState() {
    sortState = { pass: 0, idx: 0 };
  }

  // Bubble sort — one comparison/swap per call
  function sortStep() {
    if (arr.length <= 1) return true;

    const n = arr.length;
    if (!sortState) initSortState();

    const { pass, idx } = sortState;

    if (idx < n - 1 - pass) {
      // Compare adjacent elements and swap if out of order
      if (arr[idx] > arr[idx + 1]) {
        [arr[idx], arr[idx + 1]] = [arr[idx + 1], arr[idx]];
      }
      sortState.idx++;
    } else {
      // End of this pass — move to next
      sortState.pass++;
      sortState.idx = 0;

      if (sortState.pass >= n - 1) {
        return true; // Fully sorted
      }
    }

    render();
    return false;
  }

  function sorted() {
    for (let i = 1; i < arr.length; i++) {
      if (arr[i] < arr[i - 1]) return false;
    }
    return true;
  }

  // Programmatic API
  window.viz = {
    array: function() { return arr.slice(); },
    setArray: function(a) {
      arr = a.slice();
      sortState = null;
      render();
    },
    sortStep: sortStep,
    sorted: sorted
  };

  // Sort button — animate to completion
  document.getElementById('sort').addEventListener('click', function() {
    if (arr.length <= 1) return;
    initSortState();

    function step() {
      const done = window.viz.sortStep();
      render();
      if (!window.viz.sorted()) {
        requestAnimationFrame(step);
      } else {
        // Final render after sort completes
        render();
      }
    }
    requestAnimationFrame(step);
  });

  // Shuffle button — randomize the array
  document.getElementById('shuffle').addEventListener('click', function() {
    if (arr.length === 0) {
      arr = Array.from({length: 30}, () => Math.floor(Math.random() * 99) + 1);
    } else {
      shuffleArray(arr);
    }
    sortState = null;
    render();
  });

  // Reset button — restore default sorted array with random values
  document.getElementById('reset').addEventListener('click', function() {
    arr = Array.from({length: 30}, (_, i) => (i + 1) * Math.floor(Math.random() * 5) + 1);
    sortState = null;
    render();
  });

  // Initialize with random array
  document.getElementById('reset').click();
})();
</script>
</body>
</html>
